import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { CommonService } from '../../../service/common.service';
import { environment } from '../../../../environments/environment';
import { ApiNameConstants } from '../../../constant/ApiNameConstants';

interface Organization {
  id: number;
  name: string;
  avatar?: string;
  industry?: string;
  description?: string;
  website?: string;
}

interface JobDetailDto {
  id: number;
  job?: string;
  name?: string;
  address?: string;
  salary?: string;
  phone?: string;
  email?: string;
  organizationId?: number;
  organizationName?: string;
  organizationAvatar?: string;
  organizationDes?: string;
}

interface OrganizationDetailResponse {
  organization: Organization;
  jobs: JobDetailDto[];
}

@Component({
  selector: 'app-standout-brands',
  templateUrl: './standout-brands.component.html',
  styleUrls: ['./standout-brands.component.scss']
})
export class StandoutBrandsComponent implements OnInit {
  categories: string[] = ['Tất cả','Ngân hàng','Bất động sản','Xây dựng','IT - Phần mềm','Tài chính','Bán lẻ - Hàng tiêu dùng - FMCG','Sản xuất'];
  selectedCategory: string = 'Tất cả';
  organizations: Organization[] = [];
  isLoading = false;

  // UI grid
  rightGridCount = 8;
  rightGridPage = 0;
  get gridStart(): number { return this.rightGridPage * this.rightGridCount; }
  get startIndexForRight(): number { return this.organizations.length >= 2 ? 1 + this.gridStart : this.gridStart; }
  get endIndexForRight(): number { return this.startIndexForRight + this.rightGridCount; }

  // Chi tiết công ty
  selectedOrganizationDetail?: OrganizationDetailResponse;
  isDetailLoading = false;

  constructor(private commonService: CommonService, private router: Router) {}

  ngOnInit(): void {
    this.createSampleData();
  }

  private allOrganizations: Organization[] = [];
  private createSampleData(): void {
    this.allOrganizations = [
      { id: 1, name: 'Techcombank', avatar: 'https://logo.clearbit.com/techcombank.com.vn', industry: 'Ngân hàng' },
      { id: 2, name: 'VPBank', avatar: 'https://logo.clearbit.com/vpbank.com.vn', industry: 'Ngân hàng' },
      { id: 3, name: 'Viettel Group', avatar: 'https://logo.clearbit.com/viettel.com.vn', industry: 'Viễn thông' },
      { id: 4, name: 'TMA Solutions', avatar: 'https://logo.clearbit.com/tmasolutions.com', industry: 'IT - Phần mềm' },
      { id: 5, name: 'Sendo.vn', avatar: 'https://logo.clearbit.com/sendo.vn', industry: 'Bán lẻ' }
    ];
    this.organizations = [...this.allOrganizations];
  }

  onSelectCategory(cat: string): void {
    this.selectedCategory = cat;
    if (cat === 'Tất cả') {
      this.organizations = [...this.allOrganizations];
      return;
    }
    this.organizations = this.allOrganizations.filter(o => (o.industry || '').toLowerCase().includes(cat.toLowerCase()));
  }

  onNext(): void {
    const total = Math.max(this.organizations.length - 1, 0);
    const maxPage = Math.max(Math.ceil(total / this.rightGridCount) - 1, 0);
    if (this.rightGridPage < maxPage) this.rightGridPage++;
  }

  onPrev(): void {
    if (this.rightGridPage > 0) this.rightGridPage--;
  }

  onClickCompany(org: Organization): void {
    if (!org?.id) return;

    this.isDetailLoading = true;
    const apiUrl = environment.API_URI + ApiNameConstants.BS_JOBS_BY_ORG;
    const body = { organizationId: org.id };

    this.commonService.postDatas(body, apiUrl, 'getOrganizationDetail', 'Lấy chi tiết công ty')
      .subscribe({
        next: (res: OrganizationDetailResponse) => {
          this.selectedOrganizationDetail = res;
          this.isDetailLoading = false;
        },
        error: (err) => {
          console.error(err);
          this.isDetailLoading = false;
        }
      });
  }
}
